import json, os, time
TASK_NAME = {{training_run.task_name}}
ROBOT_PATH = {{primary_robot.path}}
NUM_ENVS = {{primary_robot.n_envs}}
NUM_STEPS = {{training_run.num_steps}}
RUN_DIR = {{training_run.checkpoint_dir}}
RESULT_FILE = {{checkpoint_store.result_file}}
MIN_STEPS_FOR_SUCCESS = {{training_run.min_steps_for_success}}
os.makedirs(RUN_DIR, exist_ok=True)
vram_check = check_vram_headroom(operation="train", num_envs=NUM_ENVS, complexity="medium")
if isinstance(vram_check, dict) and vram_check.get("oom_risk", False):
    raise RuntimeError(f"VRAM pre-check failed: {vram_check.get('message')}")
env_cfg = create_isaaclab_env(task_name=TASK_NAME, robot_path=ROBOT_PATH, task_type="locomotion", num_envs=NUM_ENVS, env_spacing={{primary_robot.env_spacing}})
launch_result = launch_training(task=TASK_NAME, algo={{training_run.algo}}, num_steps=NUM_STEPS, num_envs=NUM_ENVS, checkpoint_dir=RUN_DIR)
run_id = launch_result.get("run_id", TASK_NAME) if isinstance(launch_result, dict) else TASK_NAME
steps_completed = 0
latest_reward = 0.0
for _ in range(30):
    status = get_training_status(run_id=run_id, log_dir=RUN_DIR)
    if isinstance(status, dict):
        steps_completed = status.get("step") or status.get("steps_completed", 0) or 0
        latest_reward = status.get("latest_reward", 0.0) or 0.0
        if steps_completed >= MIN_STEPS_FOR_SUCCESS or status.get("state") in ("finished", "crashed"):
            break
    time.sleep(10)
pause_training(run_id=run_id)
STOCK_REWARD_CODE = "# IsaacLab stock reward for {} \ndef stock_reward(env, robot, command):\n    return env.cfg.rewards".format(TASK_NAME)
eval_result = evaluate_reward(reward_code=STOCK_REWARD_CODE, env_id=TASK_NAME, num_steps=200)
fitness = eval_result.get("fitness", 0.0) if isinstance(eval_result, dict) else 0.0
checkpoint = checkpoint_training(run_id=run_id, include_replay_buffer=False, tag={{training_run.checkpoint_tag}})
checkpoint_path = checkpoint.get("checkpoint_path", RUN_DIR + "/baseline_v1.pt") if isinstance(checkpoint, dict) else RUN_DIR + "/baseline_v1.pt"
forgetting_report = None
try:
    forgetting_report = monitor_forgetting(checkpoint_dir=RUN_DIR, base_model="isaaclab_anymal_velocity_baseline_v0")
except Exception as exc:
    print(f"[INFO] monitor_forgetting no-op for non-GR00T checkpoint: {exc!r}")
suggestions = suggest_parameter_adjustment(gap_report={"per_joint_error": [0.0]*12, "ee_cartesian_error": 0.0, "observation_distribution_gap": 0.0, "context": {"run_id": run_id, "steps_completed": steps_completed, "latest_reward": latest_reward, "fitness": fitness}})
steps_ok = steps_completed >= MIN_STEPS_FOR_SUCCESS
checkpoint_ok = bool(checkpoint_path)
fitness_ok = fitness != 0
with open(RESULT_FILE, "w") as f:
    json.dump({"task_name": TASK_NAME, "steps_completed": steps_completed, "latest_reward": latest_reward, "fitness": fitness, "checkpoint_path": str(checkpoint_path), "success": steps_ok and checkpoint_ok and fitness_ok}, f, indent=2, default=str)
assert os.path.exists(RESULT_FILE)
